import React from 'react';
import {useReactTable, getCoreRowModel, getSortedRowModel, createColumnHelper} from '@tanstack/react-table';
import type {SortingState, RowSelectionState, ColumnDef, VisibilityState} from '@tanstack/react-table';
import {BaseTable} from '@gravity-ui/table';
import {TableColumnSetup, Pagination, Checkbox, Button, ActionsPanel, Text} from '@gravity-ui/uikit';

interface User {
  id: string;
  name: string;
  email: string;
  role: string;
  createdAt: string;
}

const columnHelper = createColumnHelper<User>();

function makeColumns(
  rowSelection: RowSelectionState,
  onToggleRow: (id: string) => void,
  onToggleAll: (checked: boolean) => void,
  allSelected: boolean,
  someSelected: boolean,
) {
  return [
    columnHelper.display({
      id: '_selection',
      header: () => (
        <Checkbox
          checked={allSelected}
          indeterminate={!allSelected && someSelected}
          onUpdate={onToggleAll}
        />
      ),
      cell: ({row}) => (
        <Checkbox
          checked={row.getIsSelected()}
          onUpdate={() => onToggleRow(row.id)}
        />
      ),
      size: 40,
      enableSorting: false,
    }),
    columnHelper.accessor('name', {
      header: 'Name',
      enableSorting: true,
    }),
    columnHelper.accessor('email', {
      header: 'Email',
      enableSorting: true,
    }),
    columnHelper.accessor('role', {
      header: 'Role',
      enableSorting: true,
    }),
    columnHelper.accessor('createdAt', {
      header: 'Created',
      enableSorting: true,
    }),
  ];
}

export function AdvancedDataGrid({data, onDelete, onExport}: {
  data: User[];
  onDelete: (ids: string[]) => void;
  onExport: (ids: string[]) => void;
}) {
  const [sorting, setSorting] = React.useState<SortingState>([]);
  const [rowSelection, setRowSelection] = React.useState<RowSelectionState>({});
  const [columnVisibility, setColumnVisibility] = React.useState<VisibilityState>({});
  const [page, setPage] = React.useState(1);
  const [pageSize, setPageSize] = React.useState(20);

  const paginatedData = React.useMemo(() => {
    const start = (page - 1) * pageSize;
    return data.slice(start, start + pageSize);
  }, [data, page, pageSize]);

  const selectedIds = Object.keys(rowSelection).filter((k) => rowSelection[k]);
  const allSelected = paginatedData.length > 0 && paginatedData.every((_, i) => rowSelection[String(i)]);
  const someSelected = paginatedData.some((_, i) => rowSelection[String(i)]);

  const toggleRow = React.useCallback((id: string) => {
    setRowSelection((prev) => ({...prev, [id]: !prev[id]}));
  }, []);

  const toggleAll = React.useCallback((checked: boolean) => {
    if (checked) {
      const next: RowSelectionState = {};
      paginatedData.forEach((_, i) => { next[String(i)] = true; });
      setRowSelection(next);
    } else {
      setRowSelection({});
    }
  }, [paginatedData]);

  const columns = React.useMemo(
    () => makeColumns(rowSelection, toggleRow, toggleAll, allSelected, someSelected),
    [rowSelection, toggleRow, toggleAll, allSelected, someSelected],
  );

  const table = useReactTable({
    data: paginatedData,
    columns,
    state: {sorting, rowSelection, columnVisibility},
    onSortingChange: setSorting,
    onRowSelectionChange: setRowSelection,
    onColumnVisibilityChange: setColumnVisibility,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: getSortedRowModel(),
    getRowId: (row) => row.id,
  });

  const columnSetupItems = table.getAllLeafColumns()
    .filter((col) => col.id !== '_selection')
    .map((col) => ({
      id: col.id,
      title: typeof col.columnDef.header === 'string' ? col.columnDef.header : col.id,
      selected: col.getIsVisible(),
      required: col.id === 'name',
    }));

  const handleColumnSetupUpdate = (items: typeof columnSetupItems) => {
    const next: VisibilityState = {};
    items.forEach((item) => { next[item.id] = item.selected; });
    setColumnVisibility(next);
  };

  const handlePageUpdate = (nextPage: number, nextPageSize: number) => {
    if (nextPageSize !== pageSize) {
      setPageSize(nextPageSize);
      setPage(1);
    } else {
      setPage(nextPage);
    }
  };

  return (
    <div>
      <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16}}>
        <Text variant="subheader-2">{data.length} users</Text>
        <div style={{display: 'flex', gap: 8}}>
          <TableColumnSetup
            items={columnSetupItems}
            onUpdate={handleColumnSetupUpdate}
            sortable
            showStatus
          />
        </div>
      </div>

      <BaseTable
        table={table}
        stickyHeader
        emptyContent={<Text color="secondary">No data available</Text>}
      />

      <div style={{marginTop: 16}}>
        <Pagination
          page={page}
          pageSize={pageSize}
          total={data.length}
          pageSizeOptions={[10, 20, 50, 100]}
          onUpdate={handlePageUpdate}
        />
      </div>

      {selectedIds.length > 0 && (
        <ActionsPanel
          actions={[
            {id: 'delete', text: 'Delete selected', handler: () => onDelete(selectedIds), theme: 'danger'},
            {id: 'export', text: 'Export selected', handler: () => onExport(selectedIds)},
          ]}
          onClose={() => setRowSelection({})}
          renderNote={() => `${selectedIds.length} item${selectedIds.length > 1 ? 's' : ''} selected`}
        />
      )}
    </div>
  );
}

import React from 'react';
import {AsideHeader, Footer, MobileHeader} from '@gravity-ui/navigation';
import {Icon} from '@gravity-ui/uikit';
import {House, Persons, Gear, ChartColumn} from '@gravity-ui/icons';
import {useLocation, useNavigate} from 'react-router-dom';

const PINNED_KEY = 'aside-pinned';

const logoIcon = House;

function useIsMobile() {
  const [isMobile, setIsMobile] = React.useState(window.innerWidth < 768);
  React.useEffect(() => {
    const mql = window.matchMedia('(max-width: 767px)');
    const handler = (e: MediaQueryListEvent) => setIsMobile(e.matches);
    mql.addEventListener('change', handler);
    return () => mql.removeEventListener('change', handler);
  }, []);
  return isMobile;
}

function useMenuItems() {
  const location = useLocation();
  const navigate = useNavigate();

  return React.useMemo(() => [
    {
      id: 'home',
      title: 'Home',
      icon: House,
      current: location.pathname === '/',
      onItemClick: () => navigate('/'),
    },
    {
      id: 'dashboard',
      title: 'Dashboard',
      icon: ChartColumn,
      current: location.pathname.startsWith('/dashboard'),
      onItemClick: () => navigate('/dashboard'),
    },
    {
      id: 'users',
      title: 'Users',
      icon: Persons,
      current: location.pathname.startsWith('/users'),
      onItemClick: () => navigate('/users'),
    },
    {
      id: 'settings',
      title: 'Settings',
      icon: Gear,
      current: location.pathname.startsWith('/settings'),
      onItemClick: () => navigate('/settings'),
    },
  ], [location.pathname, navigate]);
}

export function AppShell({children}: {children: React.ReactNode}) {
  const isMobile = useIsMobile();
  const menuItems = useMenuItems();
  const [pinned, setPinned] = React.useState(() => {
    const saved = localStorage.getItem(PINNED_KEY);
    return saved !== null ? saved === 'true' : true;
  });

  const handleChangePinned = (next: boolean) => {
    setPinned(next);
    localStorage.setItem(PINNED_KEY, String(next));
  };

  const logo = {
    icon: logoIcon,
    text: 'My App',
    href: '/',
  };

  const footerMenuItems = [
    {text: 'Documentation', href: '/docs', target: '_blank'},
    {text: 'Support', href: '/support', target: '_blank'},
  ];

  if (isMobile) {
    return (
      <>
        <MobileHeader
          logo={logo}
          menuItems={menuItems.map((item) => ({
            id: item.id,
            title: item.title,
            icon: item.icon,
            current: item.current,
            onItemClick: item.onItemClick,
          }))}
        />
        <main style={{padding: 16}}>{children}</main>
      </>
    );
  }

  return (
    <AsideHeader
      logo={logo}
      menuItems={menuItems}
      pinned={pinned}
      onChangePinned={handleChangePinned}
      isCompactMode={false}
      renderContent={({size}) => (
        <main style={{paddingLeft: size, transition: 'padding-left 0.2s'}}>
          <div style={{padding: 24, maxWidth: 1200, margin: '0 auto'}}>
            {children}
          </div>
          <Footer
            copyright={`\u00A9 ${new Date().getFullYear()} My App`}
            menuItems={footerMenuItems}
            withDivider
          />
        </main>
      )}
    />
  );
}

import React from 'react';
import {AsideHeader} from '@gravity-ui/navigation';
import {Button, Icon} from '@gravity-ui/uikit';
import {House, Gear, Moon} from '@gravity-ui/icons';

export function MinimalShell({children}: {children: React.ReactNode}) {
  const [pinned, setPinned] = React.useState(true);
  const [compact, setCompact] = React.useState(false);

  return (
    <AsideHeader
      logo={{
        icon: House,
        text: 'My App',
        href: '/',
      }}
      menuItems={[
        {id: 'home', title: 'Home', icon: House, current: true},
        {id: 'settings', title: 'Settings', icon: Gear},
      ]}
      pinned={pinned}
      onChangePinned={setPinned}
      isCompactMode={compact}
      renderFooter={({isExpanded}) => (
        <div style={{padding: 8}}>
          {isExpanded && (
            <Button
              view="flat"
              size="s"
              width="max"
              onClick={() => setCompact((prev) => !prev)}
            >
              <Icon data={Moon} size={16} />
              {compact ? 'Normal mode' : 'Compact mode'}
            </Button>
          )}
        </div>
      )}
      renderContent={() => (
        <main style={{padding: 24}}>{children}</main>
      )}
    />
  );
}

import React from 'react';
import {Button} from '@gravity-ui/uikit';
import {ConfirmDialog} from '@gravity-ui/components';

export function DeleteConfirmation({onDelete}) {
  const [open, setOpen] = React.useState(false);
  const [loading, setLoading] = React.useState(false);

  const handleConfirm = async () => {
    setLoading(true);
    try {
      await onDelete();
      setOpen(false);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Button view="outlined-danger" onClick={() => setOpen(true)}>
        Delete
      </Button>
      <ConfirmDialog
        open={open}
        onClose={() => setOpen(false)}
        title="Delete this item?"
        message="This action cannot be undone. The item and all associated data will be permanently removed."
        textButtonApply="Delete"
        textButtonCancel="Cancel"
        propsButtonApply={{view: 'outlined-danger', loading}}
        propsButtonCancel={{disabled: loading}}
        onClickButtonApply={handleConfirm}
        onClickButtonCancel={() => setOpen(false)}
      />
    </>
  );
}

import React from 'react';
import {Dialog, Button, Checkbox} from '@gravity-ui/uikit';

export function PublishConfirmation({onPublish}) {
  const [open, setOpen] = React.useState(false);
  const [notifySubscribers, setNotifySubscribers] = React.useState(true);

  return (
    <>
      <Button view="action" onClick={() => setOpen(true)}>
        Publish
      </Button>
      <Dialog open={open} onClose={() => setOpen(false)} size="s">
        <Dialog.Header caption="Publish changes?" />
        <Dialog.Body>
          Publishing will make your draft visible to all users.
          <Checkbox
            checked={notifySubscribers}
            onUpdate={setNotifySubscribers}
            style={{marginTop: 12}}
          >
            Notify subscribers
          </Checkbox>
        </Dialog.Body>
        <Dialog.Footer
          textButtonApply="Publish"
          textButtonCancel="Cancel"
          propsButtonApply={{view: 'action'}}
          onClickButtonApply={() => {
            onPublish({notifySubscribers});
            setOpen(false);
          }}
          onClickButtonCancel={() => setOpen(false)}
