import React from 'react';
import {AsideHeader} from '@gravity-ui/navigation';
import {ActionBar} from '@gravity-ui/navigation';
import {RangeCalendar} from '@gravity-ui/date-components';
import {Button, Card, Text, Popup, Icon, Breadcrumbs} from '@gravity-ui/uikit';
import {LayoutHeader, ChartColumn, Persons, Calendar as CalendarIcon, ArrowDownToLine} from '@gravity-ui/icons';
import {dateTimeParse} from '@gravity-ui/date-utils';
import type {RangeValue} from '@gravity-ui/date-components';
import type {DateTime} from '@gravity-ui/date-utils';

const MENU_ITEMS = [
  {id: 'dashboard', title: 'Dashboard', icon: LayoutHeader, onItemClick: () => {}},
  {id: 'analytics', title: 'Analytics', icon: ChartColumn, onItemClick: () => {}},
  {id: 'users', title: 'Users', icon: Persons, onItemClick: () => {}},
];

function MetricCard({title, value, trend, trendDirection}) {
  return (
    <Card view="outlined" size="l" style={{padding: 20}}>
      <Text variant="caption-1" color="secondary">{title}</Text>
      <div style={{marginTop: 4}}>
        <Text variant="header-1">{value}</Text>
      </div>
      <div style={{marginTop: 8}}>
        <Text
          variant="body-short"
          color={trendDirection === 'up' ? 'positive' : 'danger'}
        >
          {trend}
        </Text>
      </div>
    </Card>
  );
}

function DateRangeFilter({value, onUpdate}) {
  const [open, setOpen] = React.useState(false);
  const buttonRef = React.useRef(null);

  const formatRange = (range) => {
    if (!range) return 'Select dates';
    const start = range.start.format('MMM D');
    const end = range.end.format('MMM D, YYYY');
    return `${start} — ${end}`;
  };

  return (
    <>
      <Button
        ref={buttonRef}
        view="outlined"
        onClick={() => setOpen((prev) => !prev)}
      >
        <Icon data={CalendarIcon} size={16} />
        {formatRange(value)}
      </Button>
      <Popup
        anchorElement={buttonRef.current}
        open={open}
        placement="bottom-end"
        onOpenChange={(open) => { if (!open) setOpen(false); }}
      >
        <div style={{padding: 16}}>
          <RangeCalendar
            size="m"
            value={value}
            onUpdate={(newValue) => {
              onUpdate(newValue);
              setOpen(false);
            }}
          />
        </div>
      </Popup>
    </>
  );
}

