import React from 'react';
import {Table, Pagination, DropdownMenu, ActionsPanel, Label, Checkbox, Select, TextInput, Icon} from '@gravity-ui/uikit';
import {Magnifier} from '@gravity-ui/icons';

const STATUS_OPTIONS = [
  {value: 'all', content: 'All statuses'},
  {value: 'active', content: 'Active'},
  {value: 'inactive', content: 'Inactive'},
  {value: 'pending', content: 'Pending'},
];

const STATUS_THEME = {
  active: 'success',
  inactive: 'normal',
  pending: 'warning',
};

export function DataTableWithFilters({data, onEdit, onDelete, onExport}) {
  const [filter, setFilter] = React.useState('');
  const [statusFilter, setStatusFilter] = React.useState(['all']);
  const [page, setPage] = React.useState(1);
  const [pageSize, setPageSize] = React.useState(20);
  const [selectedIds, setSelectedIds] = React.useState(new Set());
  const [sortColumn, setSortColumn] = React.useState(null);
  const [sortOrder, setSortOrder] = React.useState('asc');

  // 1. Filter
  const filteredData = React.useMemo(() => {
    let result = data;
    if (filter) {
      const lc = filter.toLowerCase();
      result = result.filter((row) =>
        row.name.toLowerCase().includes(lc) ||
        row.email.toLowerCase().includes(lc)
      );
    }
    if (statusFilter[0] !== 'all') {
      result = result.filter((row) => row.status === statusFilter[0]);
    }
    return result;
  }, [data, filter, statusFilter]);

  // 2. Sort
  const sortedData = React.useMemo(() => {
    if (!sortColumn) return filteredData;
    return [...filteredData].sort((a, b) => {
      const valA = a[sortColumn] ?? '';
      const valB = b[sortColumn] ?? '';
      const cmp = String(valA).localeCompare(String(valB));
      return sortOrder === 'asc' ? cmp : -cmp;
    });
  }, [filteredData, sortColumn, sortOrder]);

  // 3. Paginate
  const paginatedRows = React.useMemo(() => {
    const start = (page - 1) * pageSize;
    return sortedData.slice(start, start + pageSize);
  }, [sortedData, page, pageSize]);

  const pageIds = new Set(paginatedRows.map((row) => row.id));
  const allPageSelected = paginatedRows.length > 0 && paginatedRows.every((row) => selectedIds.has(row.id));

  const toggleRow = (id) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (allPageSelected) {
        pageIds.forEach((id) => next.delete(id));
      } else {
        pageIds.forEach((id) => next.add(id));
      }
      return next;
    });
  };

  const clearSelection = () => setSelectedIds(new Set());

  const handlePageUpdate = (nextPage, nextPageSize) => {
    if (nextPageSize !== pageSize) {
      setPageSize(nextPageSize);
      setPage(1);
    } else {
      setPage(nextPage);
    }
  };

  const columns = [
    {
      id: '_selection',
      name: () => (
        <Checkbox
          checked={allPageSelected}
          indeterminate={!allPageSelected && paginatedRows.some((r) => selectedIds.has(r.id))}
          onUpdate={toggleAll}
        />
      ),
      template: (row) => (
        <Checkbox
          checked={selectedIds.has(row.id)}
          onUpdate={() => toggleRow(row.id)}
        />
      ),
      width: 40,
      sticky: 'start',
    },
    {id: 'name', name: 'Name'},
    {id: 'email', name: 'Email'},
    {
      id: 'status',
      name: 'Status',
      template: (row) => (
        <Label theme={STATUS_THEME[row.status] || 'normal'}>
          {row.status.charAt(0).toUpperCase() + row.status.slice(1)}
        </Label>
      ),
    },
    {id: 'createdAt', name: 'Created'},
    {
      id: '_actions',
      name: '',
      template: (row) => (
        <DropdownMenu
          items={[
            {text: 'Edit', action: () => onEdit(row)},
            {text: 'Duplicate', action: () => onEdit({...row, id: undefined})},
            {text: 'Delete', action: () => onDelete([row.id]), theme: 'danger'},
          ]}
          size="s"
        />
      ),
      width: 60,
      sticky: 'end',
    },
  ];

  return (
    <div>
      <div style={{display: 'flex', gap: 12, alignItems: 'center', marginBottom: 16}}>
        <TextInput
          value={filter}
          onUpdate={setFilter}
          placeholder="Search by name or email..."
          hasClear
          leftContent={<Icon data={Magnifier} size={16} />}
          style={{maxWidth: 360}}
        />
        <Select
          value={statusFilter}
          onUpdate={setStatusFilter}
          options={STATUS_OPTIONS}
          placeholder="All statuses"
          width={180}
        />
      </div>

      <Table
        data={paginatedRows}
        columns={columns}
        getRowId={(row) => row.id}
        emptyMessage="No results match your filters"
        edgePadding
        stickyHorizontalScroll
      />

      <div style={{marginTop: 16}}>
        <Pagination
          page={page}
          pageSize={pageSize}
          total={filteredData.length}
          pageSizeOptions={[10, 20, 50, 100]}
          onUpdate={handlePageUpdate}
        />
      </div>

      {selectedIds.size > 0 && (
        <ActionsPanel
          actions={[
            {id: 'delete', text: 'Delete selected', handler: () => onDelete([...selectedIds]), theme: 'danger'},
            {id: 'export', text: 'Export selected', handler: () => onExport([...selectedIds])},
          ]}
          onClose={clearSelection}
          renderNote={() => `${selectedIds.size} item${selectedIds.size > 1 ? 's' : ''} selected`}
        />
      )}
    </div>
  );
}

import React from 'react';
import {RangeCalendar, DateField} from '@gravity-ui/date-components';
import {Button, Popup, Label} from '@gravity-ui/uikit';
import {dateTime, dateTimeParse} from '@gravity-ui/date-utils';

const PRESETS = [
  {
    label: 'Last 7 days',
    getRange: () => ({
      start: dateTime().subtract(7, 'days'),
      end: dateTime(),
    }),
  },
  {
    label: 'Last 30 days',
    getRange: () => ({
      start: dateTime().subtract(30, 'days'),
      end: dateTime(),
    }),
  },
  {
    label: 'This month',
    getRange: () => ({
      start: dateTime().startOf('month'),
      end: dateTime(),
    }),
  },
  {
    label: 'This quarter',
    getRange: () => ({
      start: dateTime().startOf('quarter'),
      end: dateTime(),
    }),
  },
];

function formatDate(dt) {
  return dt ? dt.format('MMM D, YYYY') : '';
}

export function DateRangeFilter({value, onUpdate}) {
  const triggerRef = React.useRef(null);
  const [open, setOpen] = React.useState(false);
  const [draft, setDraft] = React.useState(value);
  const [activePreset, setActivePreset] = React.useState(null);

  React.useEffect(() => {
    if (open) {
      setDraft(value);
    }
  }, [open, value]);

  const handlePresetClick = (preset) => {
    const range = preset.getRange();
    setDraft(range);
    setActivePreset(preset.label);
  };

  const handleCalendarUpdate = (range) => {
    setDraft(range);
    setActivePreset(null);
  };

  const handleStartUpdate = (start) => {
    if (start) {
      setDraft((prev) => ({...prev, start}));
      setActivePreset(null);
    }
  };

  const handleEndUpdate = (end) => {
    if (end) {
      setDraft((prev) => ({...prev, end}));
      setActivePreset(null);
    }
  };

  const handleApply = () => {
    onUpdate(draft);
    setOpen(false);
  };

  const handleCancel = () => {
    setDraft(value);
    setActivePreset(null);
    setOpen(false);
  };

  const triggerLabel = activePreset
    ? activePreset
    : value
      ? `${formatDate(value.start)} \u2013 ${formatDate(value.end)}`
      : 'Select date range';

  return (
    <>
      <Button ref={triggerRef} view="outlined" onClick={() => setOpen(true)}>
        {triggerLabel}
      </Button>
      <Popup
        anchorElement={triggerRef.current}
        open={open}
        placement="bottom-start"
        onOpenChange={(nextOpen) => {
          if (!nextOpen) handleCancel();
        }}
      >
        <div style={{display: 'flex', padding: 16, gap: 16}}>
          <div style={{display: 'flex', flexDirection: 'column', gap: 4, minWidth: 140}}>
            {PRESETS.map((preset) => (
              <Button
                key={preset.label}
                view="flat"
                size="m"
                selected={activePreset === preset.label}
                onClick={() => handlePresetClick(preset)}
                width="max"
              >
                {preset.label}
              </Button>
            ))}
          </div>
          <div style={{display: 'flex', flexDirection: 'column', gap: 12}}>
            <div style={{display: 'flex', gap: 8}}>
              <DateField
                label="From"
                value={draft?.start ?? null}
                onUpdate={handleStartUpdate}
                size="m"
                format="MM/DD/YYYY"
                hasClear
              />
              <DateField
                label="To"
                value={draft?.end ?? null}
                onUpdate={handleEndUpdate}
                size="m"
                format="MM/DD/YYYY"
                hasClear
              />
            </div>
            <RangeCalendar
              value={draft ?? undefined}
              onUpdate={handleCalendarUpdate}
              size="m"
            />
            <div style={{display: 'flex', justifyContent: 'flex-end', gap: 8}}>
              <Button view="flat" size="m" onClick={handleCancel}>
                Cancel
              </Button>
              <Button view="action" size="m" onClick={handleApply}>
                Apply
              </Button>
            </div>
          </div>
        </div>
      </Popup>
    </>
  );
}

