import React from 'react';
import {FilePreview, Progress, Button, Icon, Text, Card, Alert} from '@gravity-ui/uikit';
import {ArrowUpFromLine, TrashBin, Xmark, ArrowRotateLeft} from '@gravity-ui/icons';

const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10 MB
const ALLOWED_TYPES = ['image/png', 'image/jpeg', 'application/pdf'];

function validateFile(file) {
  if (!ALLOWED_TYPES.includes(file.type)) {
    return `Unsupported file type: ${file.type}`;
  }
  if (file.size > MAX_FILE_SIZE) {
    return `File too large: ${(file.size / 1024 / 1024).toFixed(1)} MB (max 10 MB)`;
  }
  return null;
}

function uploadFile(file, onProgress) {
  const controller = new AbortController();
  const promise = new Promise((resolve, reject) => {
    const xhr = new XMLHttpRequest();
    xhr.open('POST', '/api/upload');

    controller.signal.addEventListener('abort', () => xhr.abort());

    xhr.upload.addEventListener('progress', (e) => {
      if (e.lengthComputable) {
        onProgress(Math.round((e.loaded / e.total) * 100));
      }
    });

    xhr.addEventListener('load', () => {
      if (xhr.status >= 200 && xhr.status < 300) {
        resolve(JSON.parse(xhr.responseText));
      } else {
        reject(new Error(`Upload failed: ${xhr.status}`));
      }
    });

    xhr.addEventListener('error', () => reject(new Error('Network error')));
    xhr.addEventListener('abort', () => reject(new Error('Upload cancelled')));

    const formData = new FormData();
    formData.append('file', file);
    xhr.send(formData);
  });

  return {promise, controller};
}

export function FileUploadWithPreview({onUploadComplete, maxFiles = 5}) {
  const [entries, setEntries] = React.useState([]);
  const [errors, setErrors] = React.useState([]);
  const [dragOver, setDragOver] = React.useState(false);
  const inputRef = React.useRef(null);
  const controllersRef = React.useRef({});

  const handleFiles = React.useCallback((fileList) => {
    const files = Array.from(fileList);
    const newErrors = [];
    const newEntries = [];

    files.forEach((file) => {
      const error = validateFile(file);
      if (error) {
        newErrors.push(error);
        return;
      }
      const id = `${file.name}-${Date.now()}-${Math.random()}`;
      const imageSrc = file.type.startsWith('image/') ? URL.createObjectURL(file) : undefined;
      newEntries.push({id, file, imageSrc, status: 'pending', progress: 0, error: null});
    });

    setErrors(newErrors);
    setEntries((prev) => {
      const combined = [...prev, ...newEntries].slice(0, maxFiles);
      return combined;
    });

    // Start uploads
    newEntries.forEach((entry) => startUpload(entry.id, entry.file));
  }, [maxFiles]);

  const startUpload = (id, file) => {
    setEntries((prev) =>
      prev.map((e) => (e.id === id ? {...e, status: 'uploading', progress: 0, error: null} : e)),
    );

    const {promise, controller} = uploadFile(file, (progress) => {
      setEntries((prev) => prev.map((e) => (e.id === id ? {...e, progress} : e)));
    });

    controllersRef.current[id] = controller;

    promise
      .then(() => {
        setEntries((prev) => prev.map((e) => (e.id === id ? {...e, status: 'done', progress: 100} : e)));
      })
      .catch((err) => {
        if (err.message !== 'Upload cancelled') {
          setEntries((prev) =>
            prev.map((e) => (e.id === id ? {...e, status: 'error', error: err.message} : e)),
          );
        }
      })
      .finally(() => {
        delete controllersRef.current[id];
      });
  };

  const removeEntry = (id) => {
    controllersRef.current[id]?.abort();
    setEntries((prev) => {
      const entry = prev.find((e) => e.id === id);
      if (entry?.imageSrc) URL.revokeObjectURL(entry.imageSrc);
      return prev.filter((e) => e.id !== id);
    });
  };

  const retryEntry = (id) => {
    const entry = entries.find((e) => e.id === id);
    if (entry) startUpload(id, entry.file);
  };

  const handleDrop = (e) => {
    e.preventDefault();
    setDragOver(false);
    if (e.dataTransfer.files.length) handleFiles(e.dataTransfer.files);
  };

  const progressTheme = (status) => {
    if (status === 'done') return 'success';
    if (status === 'error') return 'danger';
    return 'default';
  };

  return (
    <div>
      <Card
        view="outlined"
        style={{
          border: dragOver ? '2px dashed var(--g-color-line-brand)' : '2px dashed var(--g-color-line-generic)',
          padding: 32,
          textAlign: 'center',
          cursor: 'pointer',
          transition: 'border-color 0.15s',
          background: dragOver ? 'var(--g-color-base-brand-hover)' : undefined,
        }}
        onDragEnter={(e) => { e.preventDefault(); setDragOver(true); }}
        onDragOver={(e) => { e.preventDefault(); setDragOver(true); }}
        onDragLeave={() => setDragOver(false)}
        onDrop={handleDrop}
        onClick={() => inputRef.current?.click()}
      >
        <Icon data={ArrowUpFromLine} size={32} />
        <div style={{marginTop: 8}}>
          <Text variant="body-2">Drag files here or</Text>
        </div>
        <Button view="outlined" size="m" style={{marginTop: 8}} onClick={(e) => { e.stopPropagation(); inputRef.current?.click(); }}>
          Browse files
        </Button>
        <input
          ref={inputRef}
          type="file"
          multiple
          accept={ALLOWED_TYPES.join(',')}
          style={{display: 'none'}}
          onChange={(e) => { if (e.target.files.length) handleFiles(e.target.files); e.target.value = ''; }}
        />
        <div style={{marginTop: 8}}>
          <Text variant="caption-1" color="secondary">PNG, JPEG, PDF up to 10 MB</Text>
        </div>
      </Card>

      {errors.length > 0 && (
        <div style={{marginTop: 12}}>
          {errors.map((err, i) => (
            <Alert key={i} theme="danger" message={err} onClose={() => setErrors((prev) => prev.filter((_, j) => j !== i))} style={{marginBottom: 4}} />
          ))}
        </div>
      )}

      {entries.length > 0 && (
        <div style={{marginTop: 16, display: 'flex', flexWrap: 'wrap', gap: 12}}>
          {entries.map((entry) => (
            <div key={entry.id} style={{width: 120}}>
              <FilePreview
                file={entry.file}
                imageSrc={entry.imageSrc}
                actions={[
                  {
                    icon: <Icon data={entry.status === 'uploading' ? Xmark : TrashBin} size={14} />,
                    title: entry.status === 'uploading' ? 'Cancel' : 'Remove',
                    onClick: () => removeEntry(entry.id),
                  },
                  ...(entry.status === 'error'
                    ? [{
                        icon: <Icon data={ArrowRotateLeft} size={14} />,
                        title: 'Retry',
                        onClick: () => retryEntry(entry.id),
                      }]
                    : []),
                ]}
              />
              {entry.status !== 'done' && (
                <Progress
                  value={entry.progress}
                  theme={progressTheme(entry.status)}
                  size="s"
                />
              )}
              {entry.status === 'done' && (
                <Progress value={100} theme="success" size="s" />
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import React from 'react';
import {FilePreview, Progress, Button, Icon, Text} from '@gravity-ui/uikit';
import {ArrowUpFromLine, TrashBin} from '@gravity-ui/icons';

export function SingleFileUpload({onFileReady}) {
  const [file, setFile] = React.useState(null);
  const [progress, setProgress] = React.useState(0);
  const [uploading, setUploading] = React.useState(false);
  const inputRef = React.useRef(null);

  const handleSelect = (e) => {
    const selected = e.target.files[0];
    if (!selected) return;
    setFile(selected);
    setProgress(0);
    onFileReady?.(selected);
    e.target.value = '';
  };

  const handleRemove = () => {
    setFile(null);
    setProgress(0);
    setUploading(false);
  };

  return (
    <div>
      {!file ? (
        <div>
          <Button view="outlined" onClick={() => inputRef.current?.click()}>
            <Icon data={ArrowUpFromLine} size={16} />
            Choose file
          </Button>
          <input
            ref={inputRef}
            type="file"
            style={{display: 'none'}}
            onChange={handleSelect}
          />
        </div>
      ) : (
        <div style={{width: 120}}>
          <FilePreview
            file={file}
            view="compact"
            imageSrc={file.type.startsWith('image/') ? URL.createObjectURL(file) : undefined}
            actions={[{
              icon: <Icon data={TrashBin} size={14} />,
              title: 'Remove',
              onClick: handleRemove,
            }]}
          />
          {uploading && (
            <Progress value={progress} size="s" text={`${progress}%`} />
          )}
        </div>
      )}
    </div>
  );
}

