import React from 'react';
import {TextInput, Select, Checkbox, Button, Text} from '@gravity-ui/uikit';
import {FormRow} from '@gravity-ui/components';

const ROLE_OPTIONS = [
  {value: 'developer', content: 'Developer'},
  {value: 'designer', content: 'Designer'},
  {value: 'manager', content: 'Manager'},
];

function validateEmail(value: string): string | undefined {
  if (!value) return 'Email is required';
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) return 'Enter a valid email address';
  return undefined;
}

function validateRequired(label: string) {
  return (value: string): string | undefined => {
    if (!value.trim()) return `${label} is required`;
    return undefined;
  };
}

function validateMinLength(min: number, label: string) {
  return (value: string): string | undefined => {
    if (value.length < min) return `${label} must be at least ${min} characters`;
    return undefined;
  };
}

export function RegistrationForm({onSubmit}: {onSubmit: (data: Record<string, string>) => Promise<void>}) {
  const [values, setValues] = React.useState({name: '', email: '', role: '', password: ''});
  const [agreed, setAgreed] = React.useState(false);
  const [touched, setTouched] = React.useState<Record<string, boolean>>({});
  const [submitting, setSubmitting] = React.useState(false);

  const validators: Record<string, Array<(v: string) => string | undefined>> = {
    name: [validateRequired('Name'), validateMinLength(2, 'Name')],
    email: [validateEmail],
    role: [validateRequired('Role')],
    password: [validateRequired('Password'), validateMinLength(8, 'Password')],
  };

  const getError = (field: string): string | undefined => {
    const fieldValidators = validators[field] || [];
    for (const validate of fieldValidators) {
      const error = validate(values[field as keyof typeof values]);
      if (error) return error;
    }
    return undefined;
  };

  const errors = {
    name: getError('name'),
    email: getError('email'),
    role: getError('role'),
    password: getError('password'),
  };

  const isValid = !errors.name && !errors.email && !errors.role && !errors.password && agreed;

  const handleUpdate = (field: string) => (value: string | string[]) => {
    const val = Array.isArray(value) ? value[0] || '' : value;
    setValues((prev) => ({...prev, [field]: val}));
  };

  const handleBlur = (field: string) => () => {
    setTouched((prev) => ({...prev, [field]: true}));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setTouched({name: true, email: true, role: true, password: true});
    if (!isValid) return;
    setSubmitting(true);
    try {
      await onSubmit(values);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} noValidate style={{maxWidth: 480, display: 'flex', flexDirection: 'column', gap: 16}}>
      <Text variant="header-1">Create Account</Text>

      <FormRow label="Name" fieldId="reg-name" required>
        <TextInput
          id="reg-name"
          value={values.name}
          onUpdate={handleUpdate('name')}
          onBlur={handleBlur('name')}
          validationState={touched.name && errors.name ? 'invalid' : undefined}
          errorMessage={touched.name ? errors.name : undefined}
          errorPlacement="outside"
          placeholder="Your full name"
        />
      </FormRow>

      <FormRow label="Email" fieldId="reg-email" required>
        <TextInput
          id="reg-email"
          type="email"
          value={values.email}
          onUpdate={handleUpdate('email')}
          onBlur={handleBlur('email')}
          validationState={touched.email && errors.email ? 'invalid' : undefined}
          errorMessage={touched.email ? errors.email : undefined}
          errorPlacement="outside"
          placeholder="you@example.com"
        />
      </FormRow>

      <FormRow label="Role" fieldId="reg-role" required>
        <Select
          value={values.role ? [values.role] : []}
          onUpdate={handleUpdate('role')}
          onBlur={handleBlur('role')}
          options={ROLE_OPTIONS}
          placeholder="Select a role"
          validationState={touched.role && errors.role ? 'invalid' : undefined}
          errorMessage={touched.role ? errors.role : undefined}
          width="max"
        />
      </FormRow>

      <FormRow label="Password" fieldId="reg-password" required>
        <TextInput
          id="reg-password"
          type="password"
          value={values.password}
          onUpdate={handleUpdate('password')}
          onBlur={handleBlur('password')}
          validationState={touched.password && errors.password ? 'invalid' : undefined}
          errorMessage={touched.password ? errors.password : undefined}
          errorPlacement="outside"
          placeholder="At least 8 characters"
        />
      </FormRow>

      <div>
        <Checkbox checked={agreed} onUpdate={setAgreed} size="m">
          I agree to the Terms of Service
        </Checkbox>
        {touched.name && !agreed && (
          <Text variant="caption-1" color="danger" style={{marginTop: 4}}>
            You must agree to the terms
          </Text>
        )}
      </div>

      <Button view="action" type="submit" size="l" disabled={!isValid} loading={submitting} width="max">
        Create Account
      </Button>
    </form>
  );
}

