export function ProjectWizard({onSubmit, onCancel}: {onSubmit: (data: WizardData) => Promise<void>; onCancel: () => void}) {
  const [currentStep, setCurrentStep] = React.useState(0);
  const [completedSteps, setCompletedSteps] = React.useState<Set<number>>(new Set());
  const [submitting, setSubmitting] = React.useState(false);
  const [touched, setTouched] = React.useState<Record<string, boolean>>({});
  const [data, setData] = React.useState<WizardData>({
    projectName: '',
    region: '',
    description: '',
    enableNotifications: true,
  });

  const handleUpdate = (patch: Partial<WizardData>) => {
    setData((prev) => ({...prev, ...patch}));
  };

  const handleBlur = (field: string) => {
    setTouched((prev) => ({...prev, [field]: true}));
  };

  const getStepErrors = (step: number): Record<string, string | undefined> => {
    switch (step) {
      case 0:
        return {
          projectName: !data.projectName.trim() ? 'Project name is required' : undefined,
        };
      case 1:
        return {
          region: !data.region ? 'Region is required' : undefined,
        };
      default:
        return {};
    }
  };

  const stepErrors = getStepErrors(currentStep);
  const isStepValid = Object.values(stepErrors).every((e) => !e);

  const handleNext = () => {
    // Touch all fields in current step to show errors
    const fieldsToTouch = currentStep === 0 ? ['projectName'] : currentStep === 1 ? ['region'] : [];
    setTouched((prev) => {
      const next = {...prev};
      fieldsToTouch.forEach((f) => { next[f] = true; });
      return next;
    });

    if (!isStepValid) return;

    setCompletedSteps((prev) => new Set([...prev, currentStep]));
    setCurrentStep((prev) => Math.min(prev + 1, STEPS.length - 1));
  };

  const handleBack = () => {
    setCurrentStep((prev) => Math.max(prev - 1, 0));
  };

  const handleSubmit = async () => {
    if (!isStepValid) return;
    setSubmitting(true);
    try {
      await onSubmit(data);
    } finally {
      setSubmitting(false);
    }
  };

  const isLastStep = currentStep === STEPS.length - 1;

  return (
    <div style={{maxWidth: 560, display: 'flex', flexDirection: 'column', gap: 24}}>
      <Stepper value={STEPS[currentStep].id} size="m">
        {STEPS.map((step, i) => (
          <Stepper.Item
            key={step.id}
            id={step.id}
            view={completedSteps.has(i) ? 'success' : undefined}
          >
            {step.label}
          </Stepper.Item>
        ))}
      </Stepper>

      <div style={{minHeight: 200}}>
        {currentStep === 0 && (
          <StepBasics
            data={data}
            onUpdate={handleUpdate}
            errors={stepErrors}
            touched={touched}
            onBlur={handleBlur}
          />
        )}
        {currentStep === 1 && (
          <StepConfig
            data={data}
            onUpdate={handleUpdate}
            errors={stepErrors}
            touched={touched}
            onBlur={handleBlur}
          />
        )}
        {currentStep === 2 && <StepReview data={data} />}
      </div>

      <div style={{display: 'flex', justifyContent: 'space-between'}}>
        <Button
          view="outlined"
          size="l"
          onClick={currentStep === 0 ? onCancel : handleBack}
          disabled={submitting}
        >
          {currentStep === 0 ? 'Cancel' : 'Back'}
        </Button>
        <Button
          view="action"
          size="l"
          onClick={isLastStep ? handleSubmit : handleNext}
          loading={submitting}
        >
          {isLastStep ? 'Create Project' : 'Next'}
        </Button>
      </div>
    </div>
  );
}

