import React from 'react';
import {TextInput, Popup, List, Loader, Hotkey, Icon, Text} from '@gravity-ui/uikit';
import {Magnifier} from '@gravity-ui/icons';

function useDebounce(value, delay) {
  const [debounced, setDebounced] = React.useState(value);
  React.useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);
  return debounced;
}

export function SearchWithSuggestions({onSelect, fetchSuggestions}) {
  const inputRef = React.useRef(null);
  const wrapperRef = React.useRef(null);
  const [query, setQuery] = React.useState('');
  const [suggestions, setSuggestions] = React.useState([]);
  const [isLoading, setIsLoading] = React.useState(false);
  const [showPopup, setShowPopup] = React.useState(false);
  const [activeIndex, setActiveIndex] = React.useState(0);

  const debouncedQuery = useDebounce(query, 300);

  // Fetch suggestions when debounced query changes
  React.useEffect(() => {
    if (!debouncedQuery.trim()) {
      setSuggestions([]);
      setShowPopup(false);
      return;
    }

    let cancelled = false;
    setIsLoading(true);
    setShowPopup(true);

    fetchSuggestions(debouncedQuery)
      .then((results) => {
        if (!cancelled) {
          setSuggestions(results);
          setActiveIndex(0);
          setIsLoading(false);
        }
      })
      .catch(() => {
        if (!cancelled) {
          setSuggestions([]);
          setIsLoading(false);
        }
      });

    return () => { cancelled = true; };
  }, [debouncedQuery, fetchSuggestions]);

  // Global Cmd+K / Ctrl+K hotkey
  React.useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault();
        inputRef.current?.focus();
      }
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, []);

  const handleSelect = (item) => {
    onSelect(item);
    setQuery(item.title || item.name || '');
    setShowPopup(false);
  };

  const handleKeyDown = (e) => {
    if (!showPopup || suggestions.length === 0) return;

    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        setActiveIndex((prev) => Math.min(prev + 1, suggestions.length - 1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setActiveIndex((prev) => Math.max(prev - 1, 0));
        break;
      case 'Enter':
        e.preventDefault();
        if (suggestions[activeIndex]) {
          handleSelect(suggestions[activeIndex]);
        }
        break;
      case 'Escape':
        e.preventDefault();
        setShowPopup(false);
        break;
    }
  };

  const handleUpdate = (value) => {
    setQuery(value);
    if (!value.trim()) {
      setShowPopup(false);
      setSuggestions([]);
    }
  };

  return (
    <div ref={wrapperRef} style={{position: 'relative', maxWidth: 480}}>
      <TextInput
        controlRef={inputRef}
        value={query}
        onUpdate={handleUpdate}
        onKeyDown={handleKeyDown}
        onFocus={() => {
          if (suggestions.length > 0) setShowPopup(true);
        }}
        placeholder="Search..."
        hasClear
        size="l"
        leftContent={<Icon data={Magnifier} size={16} />}
        rightContent={
          !query ? <Hotkey value="mod+k" view="light" /> : undefined
        }
      />
      <Popup
        anchorElement={wrapperRef.current}
        open={showPopup}
        placement="bottom-start"
        onOpenChange={(open) => {
          if (!open) setShowPopup(false);
        }}
        disableEscapeKeyDown
      >
        <div style={{width: wrapperRef.current?.offsetWidth || 480, maxHeight: 320, overflow: 'auto', padding: '4px 0'}}>
          {isLoading ? (
            <div style={{display: 'flex', justifyContent: 'center', padding: 24}}>
              <Loader size="s" />
            </div>
          ) : suggestions.length > 0 ? (
            <List
              items={suggestions}
              itemHeight={40}
              activeItemIndex={activeIndex}
              onChangeActive={setActiveIndex}
              onItemClick={handleSelect}
              renderItem={(item, isActive) => (
                <div style={{
                  padding: '8px 12px',
                  display: 'flex',
                  alignItems: 'center',
                  gap: 8,
                  background: isActive ? 'var(--g-color-base-simple-hover)' : undefined,
                  cursor: 'pointer',
                }}>
                  <Text variant="body-1">{item.title || item.name}</Text>
                  {item.category && (
                    <Text variant="caption-1" color="secondary">{item.category}</Text>
                  )}
                </div>
              )}
            />
          ) : query.trim() ? (
            <div style={{padding: '16px 12px', textAlign: 'center'}}>
              <Text variant="body-1" color="secondary">
                No results for "{query}"
              </Text>
            </div>
          ) : null}
        </div>
      </Popup>
    </div>
  );
}

import React from 'react';
