const ALL_ITEMS = [
  {id: '1', name: 'Dashboard', category: 'Pages'},
  {id: '2', name: 'User Management', category: 'Pages'},
  {id: '3', name: 'API Settings', category: 'Settings'},
  {id: '4', name: 'Billing', category: 'Settings'},
