];

export function QuickSearch({onNavigate}) {
  const wrapperRef = React.useRef(null);
  const [query, setQuery] = React.useState('');
  const [open, setOpen] = React.useState(false);

  const filtered = React.useMemo(() => {
    if (!query.trim()) return [];
    const lc = query.toLowerCase();
    return ALL_ITEMS.filter(
      (item) => item.name.toLowerCase().includes(lc) || item.category.toLowerCase().includes(lc),
    );
  }, [query]);

  const handleUpdate = (value) => {
    setQuery(value);
    setOpen(value.trim().length > 0);
  };

  const handleSelect = (item) => {
    onNavigate(item);
    setQuery('');
    setOpen(false);
  };

  return (
    <div ref={wrapperRef} style={{maxWidth: 360}}>
      <TextInput
        value={query}
        onUpdate={handleUpdate}
        placeholder="Quick find..."
        hasClear
        leftContent={<Icon data={Magnifier} size={16} />}
      />
      <Popup
        anchorElement={wrapperRef.current}
        open={open && filtered.length > 0}
        placement="bottom-start"
        onOpenChange={(next) => { if (!next) setOpen(false); }}
      >
        <div style={{width: wrapperRef.current?.offsetWidth || 360}}>
          <List
            items={filtered}
            itemHeight={36}
            onItemClick={handleSelect}
