  compactMode: boolean;
  language: string;
  dateFormat: string;
  productUpdates: boolean;
  securityAlerts: boolean;
  digestFrequency: string;
  usageAnalytics: boolean;
  crashReports: boolean;
}

const DEFAULT_SETTINGS: SettingsValues = {
  theme: 'system',
  compactMode: false,
  language: 'en',
  dateFormat: 'YYYY-MM-DD',
  productUpdates: true,
  securityAlerts: true,
  digestFrequency: 'daily',
  usageAnalytics: true,
  crashReports: true,
};

const THEME_OPTIONS = [
  {value: 'light', content: 'Light'},
  {value: 'dark', content: 'Dark'},
  {value: 'system', content: 'System'},
];

const LANGUAGE_OPTIONS = [
  {value: 'en', content: 'English'},
  {value: 'ru', content: 'Russian'},
  {value: 'es', content: 'Spanish'},
  {value: 'de', content: 'German'},
];

const DATE_FORMAT_OPTIONS = [
  {value: 'YYYY-MM-DD', content: 'YYYY-MM-DD'},
  {value: 'DD/MM/YYYY', content: 'DD/MM/YYYY'},
  {value: 'MM/DD/YYYY', content: 'MM/DD/YYYY'},
];

const FREQUENCY_OPTIONS = [
  {value: 'immediate', content: 'Immediately'},
  {value: 'daily', content: 'Daily digest'},
  {value: 'weekly', content: 'Weekly digest'},
];

function useSettingsState(initial: SettingsValues) {
  const [saved, setSaved] = React.useState(initial);
  const [current, setCurrent] = React.useState(initial);

  const hasChanges = JSON.stringify(current) !== JSON.stringify(saved);

  const update = <K extends keyof SettingsValues>(key: K, value: SettingsValues[K]) => {
    setCurrent((prev) => ({...prev, [key]: value}));
  };

  const save = () => {
    setSaved(current);
  };

  const reset = () => {
    setCurrent(saved);
  };

  return {values: current, hasChanges, update, save, reset};
}

export function SettingsPage({
  initialSettings,
  onSave,
  onClose,
}: {
  initialSettings?: SettingsValues;
  onSave: (settings: SettingsValues) => Promise<void>;
  onClose: () => void;
}) {
  const {values, hasChanges, update, save, reset} = useSettingsState(
    initialSettings || DEFAULT_SETTINGS,
  );
  const [saving, setSaving] = React.useState(false);
  const [showDiscardConfirm, setShowDiscardConfirm] = React.useState(false);

  const handleSave = async () => {
    setSaving(true);
    try {
      await onSave(values);
      save();
    } finally {
      setSaving(false);
    }
  };

  const handleClose = () => {
    if (hasChanges) {
      setShowDiscardConfirm(true);
      return;
    }
    onClose();
  };

  return (
    <div style={{display: 'flex', flexDirection: 'column', height: '100%'}}>
      <Settings
        title="Settings"
        initialPage="appearance"
        filterPlaceholder="Search settings..."
