                <Select
                  value={[values.language]}
                  onUpdate={(v) => update('language', v[0])}
                  options={LANGUAGE_OPTIONS}
                  width={200}
                />
              </Settings.Item>
              <Settings.Item title="Date format">
                <Select
                  value={[values.dateFormat]}
                  onUpdate={(v) => update('dateFormat', v[0])}
                  options={DATE_FORMAT_OPTIONS}
                  width={200}
                />
              </Settings.Item>
            </Settings.Section>
          </Settings.Page>

          <Settings.Page id="notifications" title="Notifications">
            <Settings.Section header="Email Notifications">
              <Settings.Item title="Product updates" description="News about features and improvements">
                <Switch
                  checked={values.productUpdates}
                  onUpdate={(v) => update('productUpdates', v)}
                />
              </Settings.Item>
              <Settings.Item title="Security alerts" description="Important security-related notifications">
                <Switch
                  checked={values.securityAlerts}
                  onUpdate={(v) => update('securityAlerts', v)}
                />
              </Settings.Item>
            </Settings.Section>
            <Settings.Section header="Notification Frequency">
              <Settings.Item title="Digest frequency">
                <RadioGroup
                  value={values.digestFrequency}
                  onUpdate={(v) => update('digestFrequency', v)}
                  options={FREQUENCY_OPTIONS}
                  direction="vertical"
                />
              </Settings.Item>
            </Settings.Section>
          </Settings.Page>
        </Settings.Group>

        <Settings.Group groupTitle="Advanced">
          <Settings.Page id="privacy" title="Privacy">
            <Settings.Section header="Data Sharing">
              <Settings.Item title="Usage analytics" description="Help us improve by sharing anonymous usage data">
                <Switch
                  checked={values.usageAnalytics}
                  onUpdate={(v) => update('usageAnalytics', v)}
                />
              </Settings.Item>
              <Settings.Item title="Crash reports" description="Automatically send crash reports to help fix issues">
                <Switch
                  checked={values.crashReports}
                  onUpdate={(v) => update('crashReports', v)}
                />
              </Settings.Item>
            </Settings.Section>
          </Settings.Page>
        </Settings.Group>
      </Settings>

      <Divider />

      <div style={{display: 'flex', gap: 8, justifyContent: 'flex-end', padding: 16}}>
        <Button view="outlined" size="l" disabled={!hasChanges} onClick={reset}>
          Cancel
        </Button>
        <Button view="action" size="l" disabled={!hasChanges} loading={saving} onClick={handleSave}>
          Save Changes
        </Button>
      </div>

      <ConfirmDialog
        open={showDiscardConfirm}
        onClose={() => setShowDiscardConfirm(false)}
        title="Discard unsaved changes?"
        message="You have unsaved changes. If you leave, your changes will be lost."
        textButtonApply="Discard"
        textButtonCancel="Stay"
        propsButtonApply={{view: 'outlined-danger'}}
        onClickButtonApply={() => { setShowDiscardConfirm(false); onClose(); }}
        onClickButtonCancel={() => setShowDiscardConfirm(false)}
      />
    </div>
  );
}

