import React from 'react';
import {ThemeProvider, useTheme, Switch} from '@gravity-ui/uikit';

const THEME_KEY = 'app-theme';

function ThemeToggle() {
  const [theme, setTheme] = useTheme();

  const handleUpdate = (checked) => {
    const next = checked ? 'dark' : 'light';
    setTheme(next);
    localStorage.setItem(THEME_KEY, next);
  };

  return (
    <Switch checked={theme === 'dark'} onUpdate={handleUpdate}>
      Dark mode
    </Switch>
  );
}

function getInitialTheme() {
  if (typeof window === 'undefined') return 'system';
  return localStorage.getItem(THEME_KEY) || 'system';
}

export default function Root({children}) {
  return (
    <ThemeProvider theme={getInitialTheme()}>
      <ThemeToggle />
      {children}
    </ThemeProvider>
  );
}

import React from 'react';
import {useToaster, Button, ToasterProvider, ToasterComponent} from '@gravity-ui/uikit';

function useFeedback() {
  const {add} = useToaster();

  return React.useMemo(() => ({
    showSuccess: (title, content) =>
      add({
        name: `success-${Date.now()}`,
        title,
        content,
        theme: 'success',
        autoHiding: 5000,
        isClosable: true,
      }),
    showError: (title, content) =>
      add({
        name: `error-${Date.now()}`,
        title,
        content,
        theme: 'danger',
        autoHiding: false,
        isClosable: true,
      }),
    showWarning: (title, content) =>
      add({
        name: `warning-${Date.now()}`,
        title,
        content,
        theme: 'warning',
        autoHiding: 8000,
        isClosable: true,
      }),
  }), [add]);
}

function UserActions({userId}) {
  const feedback = useFeedback();

  const handleSave = async () => {
    try {
      await fetch(`/api/users/${userId}`, {method: 'PUT'});
      feedback.showSuccess('Saved', 'User profile updated successfully.');
    } catch (err) {
      feedback.showError('Save failed', err.message);
    }
  };

  const handleDelete = async () => {
    try {
      await fetch(`/api/users/${userId}`, {method: 'DELETE'});
      feedback.showSuccess('Deleted', 'User has been removed.');
    } catch (err) {
      feedback.showError('Delete failed', err.message);
    }
  };

  return (
    <div style={{display: 'flex', gap: 8}}>
      <Button view="action" onClick={handleSave}>Save</Button>
      <Button view="outlined-danger" onClick={handleDelete}>Delete</Button>
    </div>
  );
}

export function App() {
  return (
    <ToasterProvider>
      <UserActions userId="123" />
      <ToasterComponent />
    </ToasterProvider>
  );
}

import React from 'react';
import {Alert, Button, Popup, Icon} from '@gravity-ui/uikit';
import {Notifications} from '@gravity-ui/components';
import {Bell} from '@gravity-ui/icons';

function InlineWarning({onDismiss}) {
  return (
    <Alert
      theme="warning"
      title="API key expiring soon"
      message="Your API key expires in 3 days. Rotate it to avoid service disruption."
      view="outlined"
      onClose={onDismiss}
      actions={[
        {text: 'Rotate key', handler: () => console.log('rotate')},
      ]}
    />
  );
}

function NotificationBell({notifications, isLoading, onLoadMore}) {
  const bellRef = React.useRef(null);
  const [open, setOpen] = React.useState(false);
  const unreadCount = notifications.filter((n) => !n.read).length;

  return (
    <div style={{position: 'relative', display: 'inline-block'}}>
      <Button ref={bellRef} view="flat" size="m" onClick={() => setOpen(!open)}>
        <Icon data={Bell} size={18} />
        {unreadCount > 0 && (
          <span style={{
            position: 'absolute',
            top: 2,
            right: 2,
            background: 'var(--g-color-base-danger)',
            color: 'var(--g-color-text-light-primary)',
            borderRadius: '50%',
            width: 16,
            height: 16,
            fontSize: 10,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            {unreadCount}
          </span>
        )}
      </Button>
      <Popup
        anchorElement={bellRef.current}
        open={open}
        placement="bottom-end"
        onOpenChange={setOpen}
      >
        <div style={{width: 360, maxHeight: 480}}>
          <Notifications
            title="Notifications"
            notifications={notifications}
            isLoading={isLoading}
            emptyTitle="All caught up"
            emptyContent="No new notifications."
            onLoadMoreNotifications={onLoadMore}
          />
        </div>
      </Popup>
    </div>
  );
}

export function FeedbackExample() {
  const [showWarning, setShowWarning] = React.useState(true);

  const notifications = [
    {
      id: '1',
      content: <span>Deployment <strong>v2.4.1</strong> completed successfully.</span>,
      formattedDate: '5 minutes ago',
      read: false,
    },
    {
      id: '2',
      content: <span>User <strong>john@example.com</strong> was invited to the team.</span>,
      formattedDate: '1 hour ago',
      read: true,
    },
  ];

  return (
    <div style={{display: 'flex', flexDirection: 'column', gap: 16, padding: 24}}>
      {showWarning && <InlineWarning onDismiss={() => setShowWarning(false)} />}
      <div style={{display: 'flex', justifyContent: 'flex-end'}}>
        <NotificationBell
          notifications={notifications}
          isLoading={false}
          onLoadMore={() => Promise.resolve()}
        />
      </div>
    </div>
  );
}
